export const RunEventSink = Context.Service<RunEventSinkService>("relay/RunEventSink");

export const rendererRunEventFromRelayEvent = (
  projectPath: string,
  ticketId: string,
  runId: string,
  event: RelayCodexEvent
): RendererRunEvent => ({
  ...event,
  projectPath,
  ticketId,
  runId
});

const relayEventFromRunLogLine = (line: RunLogLine): RelayCodexEvent =>
  parseSchema(relayCodexEventSchema, {
    ...line.payload,
    type: line.type,
    timestamp: line.timestamp
  });

const parseRunLogLines = (raw: string): RunLogLine[] =>
  raw
    .split("\n")
    .filter(Boolean)
    .map((line) => parseSchema(runLogLineSchema, JSON.parse(line)));

const timestampMs = (timestamp: string | null): number | null => {
  if (!timestamp) return null;
  const parsed = Date.parse(timestamp);
  return Number.isNaN(parsed) ? null : parsed;
};

const isRecord = (value: unknown): value is Record<string, unknown> =>
  typeof value === "object" && value !== null && !Array.isArray(value);

const numberFromRecord = (record: Record<string, unknown>, keys: string[]): number | null => {
  for (const key of keys) {
    const value = record[key];
    if (typeof value === "number" && Number.isFinite(value)) return value;
  }
  return null;
};

const nestedNumberFromRecord = (record: Record<string, unknown>, parentKeys: string[], childKeys: string[]): number | null => {
  for (const parentKey of parentKeys) {
    const nested = record[parentKey];
    if (!isRecord(nested)) continue;
    const value = numberFromRecord(nested, childKeys);
    if (value !== null) return value;
  }
  return null;
};

export const summarizeRunUsage = (usage: unknown): RunUsageSummary | null => {
  if (!isRecord(usage)) return null;

  const inputTokens = numberFromRecord(usage, ["input_tokens", "inputTokens", "prompt_tokens", "promptTokens"]);
  const cachedInputTokens =
    numberFromRecord(usage, ["cached_input_tokens", "cachedInputTokens", "cached_prompt_tokens", "cachedPromptTokens"]) ??
    nestedNumberFromRecord(usage, ["input_token_details", "inputTokenDetails", "prompt_tokens_details", "promptTokensDetails"], [
      "cached_tokens",
      "cachedTokens"
    ]);
  const outputTokens = numberFromRecord(usage, ["output_tokens", "outputTokens", "completion_tokens", "completionTokens"]);
  const reasoningOutputTokens =
    numberFromRecord(usage, ["reasoning_output_tokens", "reasoningOutputTokens", "reasoning_tokens", "reasoningTokens"]) ??
    nestedNumberFromRecord(usage, ["output_token_details", "outputTokenDetails", "completion_tokens_details", "completionTokensDetails"], [
      "reasoning_tokens",
      "reasoningTokens"
    ]);
  const explicitTotal = numberFromRecord(usage, ["total_tokens", "totalTokens"]);
  const totalTokens = explicitTotal ?? (inputTokens !== null || outputTokens !== null ? (inputTokens ?? 0) + (outputTokens ?? 0) : null);

  if (
    inputTokens === null &&
    cachedInputTokens === null &&
    outputTokens === null &&
    reasoningOutputTokens === null &&
    totalTokens === null
  ) {
    return null;
  }

  return {
    inputTokens,
    cachedInputTokens,
    outputTokens,
    reasoningOutputTokens,
    totalTokens
  };
};

const isInactiveStatus = (status: RunStatus | null | undefined): status is RunStatus =>
  Boolean(status && status !== "idle" && status !== "queued" && status !== "running" && status !== "drafting");

const terminalStatusFromEvent = (event: RelayCodexEvent | null, statusOverride?: RunStatus | null): RunStatus | null => {
  if (isInactiveStatus(statusOverride)) return statusOverride;
  if (!event) return null;
  if (event.type === "run.completed") return event.finalStatus ?? "completed";
  if (event.type === "clarification.requested") return "blocked";
  if (event.type === "run.failed") {
    if (event.finalStatus) return event.finalStatus;
    const detailsCode = isRecord(event.details) && typeof event.details.code === "string" ? event.details.code : "";
    return /cancel|abort/i.test(event.message) || detailsCode === "cancelled" ? "cancelled" : "failed";
  }
  return null;
};

const isTerminalEvent = (event: RelayCodexEvent): boolean =>
  event.type === "run.completed" || event.type === "run.failed" || event.type === "clarification.requested";

export const summarizeRunLogLines = (
  ticketId: string,
  runId: string,
  lines: RunLogLine[],
  statusOverride?: RunStatus | null
): RunSummary | null => {
  if (lines.length === 0) return null;

  const entries = lines.map((line) => ({ line, event: relayEventFromRunLogLine(line) }));
  const startedEntry = entries.find(({ event }) => event.type === "run.started") ?? null;
  const terminalEntry = [...entries].reverse().find(({ event }) => isTerminalEvent(event)) ?? null;
  const latestEventAt = entries.reduce<string | null>((latest, { line }) => {
    if (!latest) return line.timestamp;
    const latestMs = timestampMs(latest) ?? 0;
    const currentMs = timestampMs(line.timestamp) ?? 0;
    return currentMs >= latestMs ? line.timestamp : latest;
  }, null);
  const finalStatus = terminalStatusFromEvent(terminalEntry?.event ?? null, statusOverride);
  const startedAt = startedEntry?.line.timestamp ?? entries[0]?.line.timestamp ?? null;
  const endedAt = terminalEntry?.line.timestamp ?? (isInactiveStatus(finalStatus) ? latestEventAt : null);
  const startMs = timestampMs(startedAt);
  const endMs = timestampMs(endedAt);
  const completedEntryWithUsage = [...entries]
    .reverse()
    .find(({ event }) => event.type === "run.completed" && event.usage !== undefined);
  const usage =
    completedEntryWithUsage?.event.type === "run.completed" ? summarizeRunUsage(completedEntryWithUsage.event.usage) : null;
  const threadId =
    (startedEntry?.event.type === "run.started" ? startedEntry.event.threadId : null) ??
    entries.find(({ line }) => line.threadId)?.line.threadId ??
    null;

  return {
    schemaVersion: RELAY_SCHEMA_VERSION,
    ticketId,
    runId,
    threadId,
    startedAt,
    endedAt,
    durationMs: startMs !== null && endMs !== null ? Math.max(0, endMs - startMs) : null,
    finalStatus,
    usage,
    eventCount: entries.length,
    latestEventAt
  };
};

export const writeRunLogEffect = (
  projectPath: string,
  ticketId: string,
  runId: string,
  threadId: string,
  event: RelayCodexEvent
): Effect.Effect<void, unknown, BackendServices> =>
  Effect.gen(function*() {
    const filePath = pathJoin(runsPath(projectPath), ticketId, `${runId}.jsonl`);
    yield* makeDirectoryEffect(pathDirname(filePath));
    const { type, timestamp, ...payload } = event;
    const record: RunLogLine = {
      schemaVersion: RELAY_SCHEMA_VERSION,
      timestamp,
      ticketId,
      runId,
      threadId,
      type,
      payload
    };
    yield* appendTextFileEffect(filePath, `${JSON.stringify(record)}\n`);
  });

export const writeRunLog = (
  projectPath: string,
  ticketId: string,
  runId: string,
  threadId: string,
  event: RelayCodexEvent
): Promise<void> => runBackendEffect(writeRunLogEffect(projectPath, ticketId, runId, threadId, event));

import { Effect } from "effect";
import { fileURLToPath } from "node:url";
import { ElectronApp } from "./electron";
import { installRelayIpcHandlers } from "./ipc";
import { RelayWindow, relayWindowPaths } from "./window/RelayWindow";
import { runBackendEffect } from "./services/runtime";
import { disposeAppRuntime, installAppRuntime } from "./services/runtime/appLayer";
import { getLogPath, logError, logInfo } from "./services/logger";
import { pathDirname } from "./services/io";
import { JobSupervisor } from "./services/kernel";

const __dirname = pathDirname(fileURLToPath(import.meta.url));
const windowOptions = relayWindowPaths(__dirname);

installAppRuntime();

process.on("uncaughtException", (error) => {
  void logError("process", "uncaught exception", error);
});

process.on("unhandledRejection", (error) => {
  void logError("process", "unhandled rejection", error);
});

const createRelayWindow = (): Promise<void> => runBackendEffect(RelayWindow.use((window) => window.createMain(windowOptions)));

const start = async (): Promise<void> => {
  await runBackendEffect(ElectronApp.use((electronApp) => electronApp.whenReady()));
  await logInfo("app", "Relay starting", { logPath: getLogPath() });
  await runBackendEffect(installRelayIpcHandlers());
  await createRelayWindow();
  const recovered = await runBackendEffect(JobSupervisor.use((supervisor) => supervisor.recoverFromRegistry()));
  if (recovered.length > 0) {
    await logInfo("app", "Recovered backend kernel executions", { count: recovered.length });
  }

  await runBackendEffect(
    Effect.gen(function*() {
      const electronApp = yield* ElectronApp;
      const relayWindow = yield* RelayWindow;

      yield* electronApp.onActivate(() => {
        void runBackendEffect(relayWindow.activate(windowOptions));
      });

      yield* electronApp.onBeforeQuit(() => {
        void disposeAppRuntime();
      });

      yield* electronApp.onWindowAllClosed(() => {
        if (electronApp.platform !== "darwin") {
          void runBackendEffect(electronApp.quit());
        }
      });
    })
  );
};

void start().catch((error) => {
  void logError("app", "Relay failed to start", error);
});
import { Context, Effect, Layer } from "effect";
import type { RendererRunEvent } from "../../shared/types";
import { ElectronWindow, type ElectronMainWindowOptions, type ElectronWindowService } from "../electron";
import { pathJoin } from "../services/io";
import { logError } from "../services/logger";

export type RelayWindowOptions = Pick<ElectronMainWindowOptions, "preloadPath" | "rendererHtmlPath" | "rendererUrl">;

export type RelayWindowService = {
  readonly createMain: (options: RelayWindowOptions) => Effect.Effect<void, unknown>;
  readonly ensureMain: (options: RelayWindowOptions) => Effect.Effect<void, unknown>;
  readonly revealOrCreateMain: (options: RelayWindowOptions) => Effect.Effect<void, unknown>;
  readonly activate: (options: RelayWindowOptions) => Effect.Effect<void, unknown>;
  readonly sendRunEvent: (event: RendererRunEvent) => Effect.Effect<void>;
  readonly destroyAll: () => Effect.Effect<void>;
};

export const RelayWindow = Context.Service<RelayWindowService>("relay/RelayWindow");

export const makeRelayWindowService = (electronWindow: ElectronWindowService): RelayWindowService => {
  const withLogging = (options: RelayWindowOptions): ElectronMainWindowOptions => ({
    ...options,
    onRendererError: (scope, error) => {
      void logError(scope, "renderer failure", error);
    }
  });

  const service: RelayWindowService = {
    createMain: (options) => electronWindow.createMainWindow(withLogging(options)),
    ensureMain: (options) =>
      Effect.gen(function*() {
        if (yield* electronWindow.hasOpenWindows()) return;
        yield* service.createMain(options);
      }),
    revealOrCreateMain: (options) =>
      Effect.gen(function*() {
        if (yield* electronWindow.hasOpenWindows()) {
          yield* electronWindow.focusMainWindow();
          return;
        }
        yield* service.createMain(options);
      }),
    activate: (options) => service.revealOrCreateMain(options),
    sendRunEvent: (event) => electronWindow.sendRunEvent(event),
    destroyAll: () => electronWindow.destroyAll()
  };

  return service;
};

export const RelayWindowLive = Layer.effect(
  RelayWindow,
  Effect.gen(function*() {
    const electronWindow = yield* ElectronWindow;
    return makeRelayWindowService(electronWindow);
  })
