+  const previousFetch = globalThis.fetch;
+  const calls: Array<{ url: string; init?: RequestInit }> = [];
+  (globalThis as { window?: unknown }).window = {
+    location: {
+      search: "?relayApiBaseUrl=http%3A%2F%2F127.0.0.1%3A12345&relayToken=test-token"
+    },
+    sessionStorage: {
+      getItem: () => null,
+      setItem: () => undefined
+    }
+  };
+  globalThis.fetch = (async (url: string | URL | Request, init?: RequestInit) => {
+    calls.push({ url: String(url), init });
+    return new Response(JSON.stringify({ ok: true, result: { ok: true } }), {
+      status: 200,
+      headers: { "Content-Type": "application/json" }
+    });
+  }) as typeof fetch;
+
+  try {
+    await relayOpenProjectInEditor({ projectPath: "/tmp/project", editorId: "vscode" });
